  ('cpa-moex-00745', 'cpa', 'cpa-moex-108-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '管理階層針對所持有之未上市（櫃）公司股票之公允價值作成單一金額估計，並於財務報表認列 為450千元，而查核人員依據所取得之查核證據，建立金額區間估計為200千元到300千元之間。 下列何者最不可能為不實表達之金額？ 100千元  150千元  200千元  250千元', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "b31a6169dd18", "answer_pdf_sha1": "13aaf559a1eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 18, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00746', 'cpa', 'cpa-moex-108-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '管理階層如未提供業已履行查核案件條款中所敘述之財務報表編製責任之書面聲明，會計師應出 具何種意見之查核報告？ 「其他事項段」加以說明此情事 「管理階層對財務報表之責任段」 「保留意見之基礎段」說明此情事 「無法表示意見之基礎段」說明此情事', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "b31a6169dd18", "answer_pdf_sha1": "13aaf559a1eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 19, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
