  ('cpa-moex-00748', 'cpa', 'cpa-moex-108-0e802df0', 'sub-cpa-03', NULL, 'single_choice', '有關查核人員於查核過程中所發現之不實表達，下列敘述何者錯誤？ 對同一科目餘額辨認出多筆不重大之不實表達，可能須重新評估該科目餘額之重大不 實表達風險 查核人員應僅累計查核過程中所辨認之重大不實表達，不用累計不重大的不實表達 查核過程中所累計之所有不實表達，以及是否已更正，應列入查核工作底稿 查核人員應與治理單位溝通每一個別重大之未更正不實表達，並應透過治理單位要求管理階層 更正查核過程所累計之所有未更正不實表達', '["", "", "", ""]'::jsonb, 1, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:09+00:00", "source_pdf_sha1": "b31a6169dd18", "answer_pdf_sha1": "13aaf559a1eb", "source_family": "moex-gov-tw", "moex": {"exam_code": "108140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "審計學", "year": "108", "exam_name": "108年專門職業及技術人員高等考試會計師、不動產估價師、專利師考試", "original_question_number": 21, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
